/**
 * Order validation — pure functions for validating order inputs and state transitions.
 *
 * Extracted from OrderService to enable reuse and independent testing.
 * These functions have no side effects and no database dependencies.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Allowed status transitions. Each key maps to the set of statuses
 * it can transition to.
 */
export const VALID_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return VALID_STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that an order has at least one item.
 * Throws if the items array is empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateOrderItems,
  VALID_STATUS_TRANSITIONS,
} from '../../src/validators/order.validator.js';
import type { OrderItem, OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any status', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('delivered', status)).toBe(false);
      }
    });

    it('should reject cancelled -> any status', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered'];
      for (const status of statuses) {
        expect(isValidStatusTransition('cancelled', status)).toBe(false);
      }
    });

    it('should reject shipped -> confirmed (backward transition)', () => {
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  describe('validateOrderItems', () => {
    it('should accept a non-empty items array', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should accept multiple items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 25 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() => validateOrderItems([])).toThrow('Order must have at least one item');
    });
  });

  describe('VALID_STATUS_TRANSITIONS', () => {
    it('should define transitions for all statuses', () => {
      const expectedStatuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      expect(Object.keys(VALID_STATUS_TRANSITIONS).sort()).toEqual(expectedStatuses.sort());
    });

    it('should have terminal states with no outgoing transitions', () => {
      expect(VALID_STATUS_TRANSITIONS.delivered).toEqual([]);
      expect(VALID_STATUS_TRANSITIONS.cancelled).toEqual([]);
    });
  });
});

